// Fork of https://github.com/andrejewski/himalaya with tweaks
const { lexer } = require('./lexer')
const { parser } = require('./parser')
const { format } = require('./format')
const { validator } = require('./validate')
const { toHTML } = require('./stringify')
const {
  voidTags,
  closingTags,
  childlessTags,
  closingTagAncestorBreakers
} = require('./tags')
const { findCode, REP_SYMBOL, ARROW_SYMBOL } = require('./utils/find-code')
const { findCodeBlocks } = require('./utils/find-code-new')
const { findComponents, CLOSE_ELEMENT_SYMBOL } = require('./utils/find-components')
const { findArrowFns,  OPEN_BRACKET, OPEN_BRACKET_PATTERN, CLOSE_BRACKET, CLOSE_BRACKET_PATTERN } = require('./utils/find-inline-arrow-fn')

const parseDefaults = {
  voidTags,
  closingTags,
  childlessTags,
  closingTagAncestorBreakers,
  includePositions: true,
}

// https://regex101.com/r/VX6RWM/1
const INLINE_CODE_FENCE = /([^`\S])(`)([^`]+)(`)([^`\S])/g

// https://regex101.com/r/UeQ049/4
const URL_OR_EMAIL = /(<)(\S*(?:https?:\/\/|[a-zA-Z0-9.!#$%&'*+\/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?))\S*)(>)/g

function formatStr(str) {


  const newCode = findCodeBlocks(str)
  /*
  console.log('newCode', newCode)
  /** */

  if (newCode.length) {
    for (let index = 0; index < newCode.length; index++) {
      const cleanCode = newCode[index]
        // .replace(/</g, REP_SYMBOL)
        .replace(/{/g, OPEN_BRACKET)
        .replace(/}/g, CLOSE_BRACKET)
        // .replace(INLINE_CODE_FENCE, `$1X$3X$5`)
      /* Disable html symbols inside code blocks */
      str = str.replace(newCode[index], cleanCode)
    }
  }

  let newString = str
    // https://regex101.com/r/Kqpl34/1 replace => arrows to avoid attribute collision
    .replace(/(=\{{1,2}\(.*\))(\s*)(\s=>\s)(.*)(})/g, `$1$2${ARROW_SYMBOL}$4$5`)
    // https://regex101.com/r/UeQ049/1 replace <http://inline-urls.com> md links
    // .replace(/<(\S*[@:]\S*)>/g, `[$1]($1)`) // as markdown link
    // https://regex101.com/r/UeQ049/2 replace <http://inline-urls.com> md links
    .replace(URL_OR_EMAIL, `${REP_SYMBOL}$2$3`)
  // console.log('newString', newString)
  
  const inlineCodeBlocks = findCode(str)
  /*
  console.log('codeBlocks', codeBlocks)
  // process.exit(1)
  /** */
  if (inlineCodeBlocks) {
    for (let index = 0; index < inlineCodeBlocks.length; index++) {
      /* Disable html symbols inside code fences */
      newString = newString
        .replace(inlineCodeBlocks[index].block, inlineCodeBlocks[index].block
          .replace(/</g, REP_SYMBOL)
          // Remove all conflicting code brackets
          // .replace(/{/g, OPEN_BRACKET)
          // .replace(/}/g, CLOSE_BRACKET)
        )
    }
  }

  const components = findComponents(newString)
  /*
  console.log('components', components)
  // process.exit(1)
  /** */
  if (components.length) {
    for (let index = 0; index < components.length; index++) {
      const cleanProps = components[index].propsRaw
        .replace(/</g, REP_SYMBOL)
        .replace(/\/>/g, CLOSE_ELEMENT_SYMBOL)
      /* Disable html symbols inside component props */
      newString = newString.replace(components[index].propsRaw, cleanProps)
    }
  }
  
  // console.log('newString', newString)
  const arrowFns = findArrowFns(newString)
  /*
  console.log('arrowFns', arrowFns)
  process.exit(1)
  /** */
  if (arrowFns) {
    for (let index = 0; index < arrowFns.length; index++) {
      const cleanArrowFn = arrowFns[index]
        // Remove all conflicting code brackets
        .replace(/{/g, OPEN_BRACKET)
        .replace(/}/g, CLOSE_BRACKET)
      // console.log('cleanArrowFn', cleanArrowFn)
      /* Disable html symbols inside arrow functions */
      newString = newString.replace(arrowFns[index], cleanArrowFn)
    }
  }
  // console.log('newString', newString)
  // console.log(newString.match(FIND_FNS))
  // return
  
  return newString
    // Fix non html entities in `backticks` https://regex101.com/r/zTMxfT/1
    .replace(/`(<)([^\/][^`\n]*)(>)`/g, `\`${REP_SYMBOL}$2$3\``)
    // Fix non html entities in "double quotes"
    .replace(/"(<)([^\/][^"\n]*)(>)"/g, `"${REP_SYMBOL}$2$3"`)
    // Fix non html entities in 'single quotes'
    .replace(/\'(<)([^\/][^'\n]*)(>)'/g, `'${REP_SYMBOL}$2$3'`)
}

function parse(str = '', opts = {}) {
  const options = Object.assign(parseDefaults, opts)
  /*
  const formattedStr = formatStr(str)
  // console.log('formattedStr', formattedStr)
  /** */
  const tokens = lexer(formatStr(str), options)
  /*
  console.log('tokens', tokens)
  /** */
  const nodes = parser(tokens, options)
  /*
  // console.log('nodes', nodes)
  /** */
  return format(nodes, options, str)
}

function stringify(ast, opts = {}) {
  const options = Object.assign(parseDefaults, opts)
  return toHTML(ast, options)
    .replace(CLOSE_BRACKET_PATTERN, '}')
    .replace(OPEN_BRACKET_PATTERN, '{')
}

function validate(strOrAst, opts = {}) {
  const ast = (typeof strOrAst === 'string') ? parse(strOrAst) : strOrAst
  const options = Object.assign(parseDefaults, opts)
  return validator(ast, options)
}

module.exports = {
  parseDefaults,
  parse,
  stringify,
  validate
}